import { useState } from 'react'
import { useQueryClient } from '@tanstack/react-query'
import {
  Box, Typography, Button, Paper, Table, TableBody, TableCell, TableContainer,
  TableHead, TableRow, IconButton, Tooltip, Dialog, DialogTitle, DialogContent,
  DialogActions, TextField, MenuItem, Chip, CircularProgress,
} from '@mui/material'
import AddIcon from '@mui/icons-material/Add'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'

// Generated by: npm run generate-api
import { useListUsers, useCreateUser, useDeleteUser, getListUsersQueryKey } from '../../api/users/users'
import { useListLabs } from '../../api/labs/labs'
import { useListCompanies } from '../../api/companies/companies'
import { useAuthStore } from '../auth/authStore'
import { hasRole, UserRole } from '../../types'

const ROLE_OPTIONS: { value: UserRole; label: string }[] = [
  { value: 'member', label: 'Member' },
  { value: 'lab_admin', label: 'Lab Admin' },
  { value: 'company_admin', label: 'Company Admin' },
]

const ROLE_COLOR: Record<string, 'default' | 'primary' | 'secondary' | 'warning'> = {
  member: 'default',
  lab_admin: 'primary',
  company_admin: 'secondary',
  super_admin: 'warning',
}

export default function UsersPage() {
  const queryClient = useQueryClient()
  const { profile } = useAuthStore()
  const canPickLab = profile ? hasRole(profile.role, 'company_admin') : false

  const [open, setOpen] = useState(false)
  const [username, setUsername] = useState('')
  const [password, setPassword] = useState('')
  const [role, setRole] = useState<UserRole>('member')
  const [labId, setLabId] = useState('')

  const { data: usersPage, isLoading } = useListUsers()
  const users = usersPage?.items ?? []
  const { data: labsPage } = useListLabs()
  const labs = labsPage?.items ?? []
  const { data: companiesPage } = useListCompanies()
  const companies = companiesPage?.items ?? []

  const { mutate: createUser, isPending: creating } = useCreateUser({
    mutation: {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: getListUsersQueryKey() })
        setOpen(false)
        setUsername('')
        setPassword('')
        setRole('member')
        setLabId('')
      },
    },
  })

  const { mutate: deleteUser } = useDeleteUser({
    mutation: {
      onSuccess: () => queryClient.invalidateQueries({ queryKey: getListUsersQueryKey() }),
    },
  })

  const handleCreate = () => {
    const lid = canPickLab ? labId : (profile?.lab?.id ?? '')
    if (!username.trim() || !password.trim() || !lid) return
    createUser({ data: { username, password, role, lab_id: lid } })
  }

  return (
    <Box sx={{ p: 3, height: '100%', overflow: 'auto' }}>
      <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
        <Typography variant="h6" fontWeight={600} sx={{ flex: 1 }}>
          Users
        </Typography>
        <Button variant="contained" startIcon={<AddIcon />} onClick={() => setOpen(true)}>
          New User
        </Button>
      </Box>

      {isLoading ? (
        <CircularProgress />
      ) : (
        <TableContainer component={Paper} elevation={1}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell sx={{ fontWeight: 600 }}>Username</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>Role</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>Company</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>Lab</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>Created</TableCell>
                <TableCell width={60} />
              </TableRow>
            </TableHead>
            <TableBody>
              {users.length === 0 && (
                <TableRow>
                  <TableCell colSpan={6}>
                    <Typography variant="body2" color="text.secondary" textAlign="center" py={2}>
                      No users yet.
                    </Typography>
                  </TableCell>
                </TableRow>
              )}
              {users.map((u) => {
                const lab = labs.find((l) => l.id === u.lab_id)
                const company = companies.find((c) => c.id === lab?.company_id)
                return (
                  <TableRow key={u.id as string} hover>
                    <TableCell>{u.username}</TableCell>
                    <TableCell>
                      <Chip
                        label={u.role}
                        size="small"
                        color={ROLE_COLOR[u.role] ?? 'default'}
                        variant="outlined"
                        sx={{ fontSize: 11 }}
                      />
                    </TableCell>
                    <TableCell>{company?.name ?? '—'}</TableCell>
                    <TableCell>{lab?.name ?? '—'}</TableCell>
                    <TableCell>{new Date(u.created_at).toLocaleDateString()}</TableCell>
                    <TableCell>
                      <Tooltip title="Delete">
                        <IconButton
                          size="small"
                          color="error"
                          disabled={u.id === profile?.id}
                          onClick={() => {
                            if (confirm(`Delete user "${u.username}"?`))
                              deleteUser({ userId: u.id as string })
                          }}
                        >
                          <DeleteOutlineIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                    </TableCell>
                  </TableRow>
                )
              })}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Dialog open={open} onClose={() => setOpen(false)} maxWidth="xs" fullWidth>
        <DialogTitle>New User</DialogTitle>
        <DialogContent>
          <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, mt: 1 }}>
            <TextField autoFocus label="Username" value={username} onChange={(e) => setUsername(e.target.value)} fullWidth size="small" />
            <TextField label="Password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} fullWidth size="small" />
            <TextField select label="Role" value={role} onChange={(e) => setRole(e.target.value as UserRole)} fullWidth size="small">
              {ROLE_OPTIONS.map((r) => (
                <MenuItem key={r.value} value={r.value}>{r.label}</MenuItem>
              ))}
            </TextField>
            {canPickLab && (
              <TextField select label="Lab" value={labId} onChange={(e) => setLabId(e.target.value)} fullWidth size="small">
                {labs.map((l) => (
                  <MenuItem key={l.id as string} value={l.id as string}>{l.name}</MenuItem>
                ))}
              </TextField>
            )}
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpen(false)}>Cancel</Button>
          <Button variant="contained" disabled={!username.trim() || !password.trim() || creating} onClick={handleCreate}>
            Create
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  )
}
